impl AsyncFees { pub fn new(executor_fee: U256, commitment_fee: U256, inclusion_fee: U256) -> Self {
    let total = executor_fee + commitment_fee + inclusion_fee;
    Self { executor_fee, commitment_fee, inclusion_fee, total }
} }

let fees = calculate_async_fees(&mut db, get_model_registry_address(), job.precompile_address, &precompile_input, Some(&spc_output), &mut model_cache)?;
